INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-02736', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會服務方案的「運作過程」（throughputs），指的是執行方案所需的各樣程序，包括了處遇、復健、支 持性的活動方法等，如諮商輔導、就業訓練、提供日托、收容安置照顧、食物分送等，為了達成某種程 度的一致性，我們必須確認並界定「運作過程」的構成要素。所謂的「運作過程」要素不包括下列那一 項敘述？', '["服務之定義（service definition）", "服務的工作項目（service tasks）", "處置方法（method of intervention）", "處置效果（intervention effect）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02737', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在臺灣，社會工作者實施社會工作服務時，面臨各種不同的評估，下列有關評估的敘述何者正確？', '["主觀的自我評估並不是社會工作執行各種服務方案後的必要工作", "量化的績效評估通常可以完整地評量社會工作者的服務績效", "行政評估對社會工作者而言，是一種非專業性的評估", "社會工作者的反省力高，主觀的自我評估就能完全改善現有困境，並不需要督導的評論與指正"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02738', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '激勵是一個複雜的心理過程，也是行動的誘因，可導致行為的激發、方向和持續。在當代的激勵理論中， Clayton Alderfer根據實證研究結果，提出人類有三種核心的需求，稱為ERG理論，此三種核心的需求不 包括下列那一項？', '["生存需求", "公平需求", "成長需求", "關係需求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02739', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '為有效管理勸募行為，妥善運用社會資源，以促進社會公益，保障捐款人權益，政府制定「公益勸募條 例」，該法第5條規定，勸募團體不包括：', '["公立學校", "行政法人", "電視台", "公益性社團法人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02740', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '隨著臺灣社會環境愈趨複雜，社會工作者所服務的個案、家庭或社區所面臨的問題或需求，會受到所處 環境的影響而有所改變，因此社會工作組織的經營必須隨著服務對象的問題或需求進行變革，下列有關 組織變革（organizational change）的敘述，那一項是社會工作者反對組織變革的理由？', '["組織變革通常從現在的狀態朝向社會工作者所期望的未來而轉變", "組織變革是一個過程，變革的速度通常太慢以致成功機會太低", "社會工作者抗拒組織變革的主要原因是「擔心變革會違反專業倫理」", "在組織變革的過程中，支持與抗拒是難免的，抗拒力量通常會贏過驅動力量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02741', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '依公益勸募條例第17條規定，勸募團體辦理勸募活動之必要支出，得於下列範圍內，由勸募活動所得支 應，下列敘述何者錯誤？', '["所得在新臺幣一千萬元以下者，為百分之十五", "所得超過新臺幣一千萬元未逾新臺幣一億元者，為新臺幣一百五十萬元加超過新臺幣一千萬元部分之 百分之八", "所得超過新臺幣一億元者，為新臺幣八百七十萬元加超過新臺幣一億元部分之百分之一", "所得超過新臺幣三億元者，為超過新臺幣一億元部分之百分之一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02742', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '人力派遣又稱為派遣勞動，這是最近在歐美日本興起的人力運用方式，在臺灣似乎也已逐漸成為一種普 及的勞動方式。下列有關人力派遣的敘述何者錯誤？', '["人力派遣的關係比傳統的僱用要複雜", "在派遣機構、用人單位與派遣勞工的三角關係中，派遣機構與派遣勞工之間為一種「商務契約關係」， 彼此約定勞務的提供與購買", "「三方關係」與「多元效忠」是人力派遣中的常見現象", "派遣機構僱用勞工的目的是要安排他們到用人單位提供勞務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02743', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列何者不是「平衡計分卡（balance scorecard, BSC）」的構面？', '["內部作業流程", "財務表現", "行動方案", "員工學習與成長"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02744', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '提供良好的服務方案以滿足服務對象的需求或解決他們所面對的問題，是社會工作者重要的任務與工作。 下列有關服務方案的設計理念敘述何者正確？', '["以成效為導向的方案規劃過程中，方案設計並不重視審慎分析和關注細節，也沒有一套必須遵守的正 式流程", "以成效為導向的方案設計並不是一個了不起的工作，而是「聘用幾個個案工作員，分派服務對象給他 們，並指示這些個案工作員提供個案服務」而已", "以成效為導向的方案規劃過程中，對各種結果的說明，我們可以視為「終結狀態」（ends）的陳述或對 方案之期待，這種「終結狀態」（ends）的陳述，我們稱為「過程目標」", "以成效為導向的方案規劃過程中，服務方案設計應被視為一種形成假設的活動，我們可以把方案假設 想成一連串的「若…則」（if-then）的命題陳述"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02745', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '依人民團體法第17條規定，設有常務理事的人民團體，理事長是如何產生的？', '["會員選舉", "由理事就常務理事中選舉", "理事互選", "會員代表選舉"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02746', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '新管理主義興起後，管理主義取代專業主義成為社會工作領域與社會服務組織矚目的焦點。晚近有一些 被視為遠離科學管理與人群關係模式革命的管理新思維出現，其中一種「指在組織中建構一個知識系統， 讓組織中的資訊與知識可以透過獲取、創造、分享、整合、記錄、存取與更新等過程，來達到不斷創新 與累積，以建構組織的智慧資本，這將有助於機構在面對外在環境的快速變遷時，能夠依據這些智慧資 本做出正確決策。」這種管理新思維稱之為：', '["時間管理", "資源管理", "品質管理", "知識管理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02747', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理者蒐集、檢視及解析特定職務的主要工作活動（如：性質、職掌與權責等），以及從事這些活動 的「人員」必備條件（如：知識、技巧、能力、資歷與態度等），並加以識別、記載、描述與分析的過 程，又稱「職能分析」。職能分析不包括下列那一個部分？', '["有關「資料」的部分", "有關「人」的部分", "有關「管理」的部分", "有關「事」的部分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02748', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '依我國志願服務法第3 條指出，民眾出於自由意志，非基於個人義務或法律責任，秉誠心以知識、體能、 勞力、經驗、技術、時間等貢獻社會，不以獲取報酬為目的，以提高公共事務效能及增進社會公益所為 之各項輔助性服務。依據內政部社會司（2005）的解釋，下列那一類人的服務工作不屬於志願服務法的 討論範疇？', '["義勇交通警察", "衛生福利部老人之家志願服務隊的志工", "醫院志工隊之志工", "社會局志工團之志工"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02749', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '人力資源部門在提供服務時，主要發揮的功能中被稱為功能性的控制（functional control）的是那一種？', '["直線功能（line function）", "幕僚功能（staff function）", "協調功能（coordinative function）", "服務功能（service function）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02750', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '當一個組織有管理職位出缺時，組織通常透過內部晉升或外部聘用兩種管道來解決，下列敘述何者是內 部晉升管道的優點？', '["可以節省薪水", "可以提升士氣與激勵員工", "可塑性高", "可以引進新的知識與技巧"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02751', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '對新進員工提供基本的背景資訊，使他們能順利完成工作，是幫助員工社會化過程的一部分，讓員工能 培養組織或其工作部門所期待的工作態度、標準、價值觀跟行為模式。這樣的人力管理活動稱為：', '["訓練（training）", "教育（education）", "員工發展（development）", "員工引導（orientation）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02752', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '科層管理是社會學家韋伯（Max Weber）所提倡的，基於理性決策的分析觀點，韋伯認為科層管理是一種 理想的組織型式。有關科層管理的敘述，下列何者錯誤？', '["科層管理具有彈性與創造力，容易因應多變的社會與個人環境", "科層管理有明確的職權準則", "科層管理易使社會工作陷入科層/專業主義的窠臼", "科層組織依才能決定升遷和報酬"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02753', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '非營利組織的財務管理計畫可分為下列四種子計畫，何者涵蓋的時間最長？', '["外部融資需求計畫", "資本預算計畫", "營運資金管理", "現金預算計畫"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02754', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '八○年代以來，隨著資訊化的潮流傳播全球，顧客的個別化，消費的多元化等趨勢顯得日益重要，一個 組織必須適應不斷變化的消費者需要，在市場上爭取消費者的信任與認同，組織才有生存與發展的機 會，社會服務機構亦復如是。彼得‧聖吉（P.M. Senge）看到這種趨勢的來臨，因此在其所著的《第五項 修鍊》一書中指出，組織唯一能夠維持長久的競爭優勢，是來自比競爭對手學得更快、更好的能力。在 其書中，他提出了一種組織型態，人們可以從他的工作中獲得生命意義、實現共同願景和獲取競爭優勢 的關鍵，請問下列何者正是他所說的組織型態？', '["科層組織", "扁平化組織", "學習型組織", "網絡型組織"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02755', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '非營利組織的會計循環分成六個步驟，下列何者是最後一個步驟？', '["分錄", "過帳", "結帳", "編製報表"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02756', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '晚近歐美國家政府的公共部門引進「新管理主義」，在政府的各層級部門力行經濟、效率與效能之 3Es。 在新管理主義的發展趨勢下，3Es也就成為組織管理所追求的目標。其中3Es中，係指讓組織能符合人們 的要求，並讓一個方案或活動達成其所定的目的或所欲的目標，是指：', '["economy（經濟）", "efficiency（效率）", "effectiveness（效能）", "enable（使能）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02757', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在方案規劃的排程中常使用到「甘特圖」，甘特圖最大的限制是：', '["不適用於需有大量作業的複雜專案", "不適合高階主管進行協調", "不容易配合財務管理", "不容易改變排程"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02758', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '開源與節流是社會福利機構及基金會增加收入、永續發展的不二法門，開源主要靠多接方案和多募款， 而節流則必須靠控制成本。有關成本的概念中，「選擇另一個方案所需放棄的利得。」稱為：', '["沉沒成本", "平均成本", "機會成本", "邊際成本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02759', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '員工的培訓方案活動需要花費許多時間與成本，因此受完訓之後對於此方案的訓練效能如何，主辦單位 會加以評估。在訓練完之後，主辦單位會發給學員一份問卷詢問學員對此次訓練的課程內容、上課安排 時間、教學方式及表達技巧、授課教材、教學設備及行政等方面的感覺與滿意程度，這種評估是做到下 列那一種層次的評估準則？', '["學習層次", "反應層次", "績效層次", "行為層次"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02760', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '方案管理者（專案經理）的主要責任不包括：', '["對目前組織的責任", "對方案（專案）與客戶（案主）的責任", "對董事會（理事會）的責任", "對方案（專案）團隊成員的責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
